(629, 21, 124, 343, 'NIGHT SHIFT', '2025-11-22', '23:46', '06:46', 197, '- led pada fixture kurang terang', '- adjust tabung pada led atur posisi dari cahaya nya \r\n- potong ujung dari tabung led supaya cahaya bisa masuk dan terang', 119, 'Adjust tabung led pass', '2025-11-21 23:52:04', '2025-12-01 06:05:29'),
(630, 21, 122, 332, 'DAY SHIFT', '2025-11-22', '06:50', '07:36', 201, 'Program yang tidak merespon unit', '1.yang pertama kita pastikan barang/unit yang fresh kita cek menggunakan terratem.pro biasanya juga ada barang yang memang usb portnya bermasalah\r\n2.jika sudah kita cek unit kita cek lagi perkabelan biasanya ada yang bermasalah terutama kabel power& kabel', 135, 'Pass', '2025-11-22 00:42:56', '2025-12-01 06:05:29'),
(632, 21, 122, 333, 'DAY SHIFT', '2025-11-22', '08:00', '08:40', 185, 'Hdmi tidak terhubung ke unit', '1.coba cek kabel hdmi dari pc ke unit\r\n2.pastikan connector hdmi pas masuk ke unit', 135, 'Pass', '2025-11-22 01:46:26', '2025-11-27 05:54:01'),
(633, 21, 122, 333, 'DAY SHIFT', '2025-11-22', '08:30', '08:49', 199, 'Unit yang tidak terdeteksi program', '1.biasanya barang seperti itu snnya doubel/ada 2\r\n2.rework sn yang bermasalah bisa kita tengok didalam log pengetesan', 135, 'Pass', '2025-11-22 01:53:30', '2025-12-01 06:05:29'),
(634, 21, 122, 333, 'DAY SHIFT', '2025-11-22', '07:00', '07:50', 198, 'Jarum yang tidak terkena/tidak terdeteksi oleh unit', '1.coba kita lihat jarum\" yang ada di fixture\r\n2,biasanya jarum\"nya kotor dan menutupi jarum yang menembak ke unit\r\n3.jika tidak bisa juga kita panggil fixture untuk menggerjakannya', 135, 'Pass', '2025-11-22 01:58:12', '2025-12-01 06:05:29'),
(635, 21, 122, 332, 'NIGHT SHIFT', '2025-11-27', '02:04', '04:04', 113, 'Jarum voltage pada mesin bengkok membuat arus listrik nya tak masuk ke titik barang', '- ganti jarum voltage pada mesin karena kemungkinan kotor ataupun bengkok\r\n- cek arus voltage pada jarum apakah menyala atau tida, jika tidak menyala masalh di ni tidak terkoneksi', 119, 'Pass setelah ganti jarum voltage pada mesin', '2025-11-27 00:09:15', '2025-11-27 05:54:01'),
(636, 21, 122, 334, 'NIGHT SHIFT', '2025-11-27', '12:09', '04:09', 113, 'Masalah di usb carrent voltage', '- jarum pada voltage relay di mesin kotor dan bengkok harus di ganti \r\n- relay pada mesin tidak terkoneksi harus cek terminal pastikan  relay nya hidup', 119, 'Jika tidak hidup maslah di relay harus cek tegangan listrik', '2025-11-27 00:20:34', '2025-11-27 05:54:01'),
(637, 21, 123, 341, 'NIGHT SHIFT', '2025-11-27', '01:20', '04:20', 183, 'Masalah di typrob pada ant 1 nilai kurang', '- ganti typrob dikarenakan typrob jarum nya sudah bengkok dan kotor \r\n-setelah di ganti coba verifikasi apakah nilai dari phatlost nya bagus', 119, '- ganti typrob pass', '2025-11-27 00:24:34', '2025-11-27 05:54:01'),
(638, 21, 124, 713, 'NIGHT SHIFT', '2025-11-27', '23:24', '06:24', 197, 'Masalah pada tabung led nilai cahaya dari led berkurang', '- potong tabung led pada mesin supaya chaya nya lebih terang dan jelas\r\n- adjust tabung led karena jarak tabung led dan barang ada jarak membuat cahaya nya jadi redup', 119, 'Adjust tabung led pass', '2025-11-27 00:30:13', '2025-12-01 06:01:07'),
(639, 21, 124, 343, 'DAY SHIFT', '2025-11-27', '07:40', '08:03', 49, 'Gambar yang tidak terdeteksi program', '1.kita check dulu perkabelannya apakah sudah oke ,biasanya connector bermasalah karena shot\r\n2.jika gambar sudah ada tapi blm juga pass, kita copy gambar yang ada di capture ke sample dilakukan saat program lagi jalan, lalu kita buka ulang program', 135, 'Pass', '2025-11-27 01:07:01', '2025-11-27 05:54:01'),
(640, 21, 123, 339, 'DAY SHIFT', '2025-11-27', '09:40', '10:20', 196, 'Nilai pada antena1 blank/ tidak terdeteksi', '1.kita harus memperhatikan dalam sederatan pada ant1 t-prop,kabel woken, db, spiliter \r\n2.pasti masalah dibagian situ saja jika sudah coba jika masih blank, coba kita tukar posisi ant1&ant2 jika tetap ant1nya yang bermasalah kita coba calibrasi ulang', 135, 'Pass', '2025-11-27 03:58:01', '2025-12-01 06:00:26'),
(644, 21, 203, 343, 'NIGHT SHIFT', '2025-11-30', '23:43', '00:43', 194, 'Pengetesan spdif tidak terkoneksi', '- cek nilai dari spdif nya jika minus berakti masalah di kabel jika kurang atau lebih nilai nya berarti masalah kurang adjust pada posis tertentu', 119, 'Ganti kabel karena sudah rusak setelah ganti pass', '2025-12-01 06:33:53', '2025-12-02 01:26:55'),
