(671, 23, 222, 513, 'NIGHT SHIFT', '2025-12-09', '22:50', '23:20', 257, 'Ada masalah pada usb check fail!', '1.coba kita lihat log nya yang ng\r\n2.kita lihat disitu nilai speed usbnya, nilai nya 19000-50000\r\n3.jika nilai nya rendah coba dahulu pindah kan ke port lain, jika masih ng coba change usbnya', 135, 'Pass', '2025-12-08 18:07:06', '2025-12-08 18:07:06'),
(672, 23, 249, 878, 'NIGHT SHIFT', '2025-12-09', '22:50', '23:30', 258, 'Gambar yang tidak muncul', '1.coba kita lihat gambar nya di capture\r\n2.jika blank coba kita bersihkan card hdmi nya ,bersihkan port cable nya , lalu coba restart pc', 135, 'Pass', '2025-12-08 18:17:52', '2025-12-08 18:17:52'),
