(619, '2026-04-10', 'Day Shift', 40, 'LINE TIDAK TARGET/UPH TIDAK TARGET\n-1.STATION RADIO BOARD HAVE 11 MACHINES\n-ALL MACHINES STOP RUNNING BECAUSE RF PN:69BK41D10B01 WAITING DIP FROM 08:10-08:50  ,11:20-12:50', 235, '2026-04-10 09:36:44'),
(620, '2026-04-10', 'Day Shift', 41, 'LINE TIDAK TARGET/UPH TIDAK TARGET\n-1.STATION RADIO BOARD HAVE 11 MACHINES\n-ALL MACHINES STOP RUNNING BECAUSE RF PN:69BK41D10B01 WAITING DIP FROM 08:10-08:50  ,11:20-12:50', 235, '2026-04-10 09:37:12'),
(621, '2026-04-10', 'Day Shift', 13, '- station FW : stabil\n- station RX board : stabil\n- station Acoustic :\n   ID : 610915 NG kabel power dari jam 13:20-13:40\n\nnote : line target', 59, '2026-04-10 10:14:15'),
