(624, '2026-04-10', 'Night Shift', 20, '- REPORT BARANG NTF YANG AKAN MASUK REPAIR SUDAH DIKERJAKAN \n- BARANG NG BURIN DAN OTA SUDAH OKE SEMUA \n- MESIN RF NO. 3 NG BEPW50 , MELAKUKAN PENUKARAN TIPROB DAN PENUKARANN DB MESIN OKE PUKUL 05.01', 69, '2026-04-10 23:15:59'),
(626, '2026-04-11', 'Night Shift', 60, 'line Target sesuai UPH', 106, '2026-04-10 23:22:32'),
(627, '2026-04-10', 'Night Shift', 22, '#. Device 613204 board station is not stable caused power suply (not good cable Dc of fixture at 12:00 - 03:00\n#. Device 613320 board station is not stable caused voltage (BSFPA1) at 22;50 - 06;50 \n#. Device 613234 nft station is not be used becaused 2G Ant 0 (BDFW53) at 22:50 - 01:30  \n#. all mechines traffic station are not stable because wan to lan (BSFI77) at 22:50 - 06:50', 76, '2026-04-10 23:43:43'),
(637, '2026-04-11', 'Day Shift', 17, 'F0.5  1 MESIN NG CAPTURE SIGNAL\n           setelah ganti T PRUP mesin berjalan \n           normal\n\nF2 RF OTA 2 mesin NG ZWAVE setelah verifykasi\n                       cari nilai baru mesin berjalan normal', 75, '2026-04-11 05:53:38'),
